import React, { useState, useEffect } from 'react';
import Navbar from '../components/Navbar';
import Footer from '../components/Footer';
import TaskCard from '../components/TaskCard';
import AddTaskModal from '../components/AddTaskModal';
import Login from './Login'; // Ab ye modal ki tarah use hoga
import Signup from './Signup'; 
import { LayoutDashboard, Users, Clock, CheckCircle2, Plus } from 'lucide-react';
import { fetchTasks } from '../api';

const Dashboard = () => {
  const [tasks, setTasks] = useState([]);
  const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
  const [authMode, setAuthMode] = useState(null); // 'login', 'signup', ya null

  const userName = localStorage.getItem('name') || 'Guest';
  const userRole = localStorage.getItem('role') || 'member';
  const token = localStorage.getItem('token');

  const getTasks = async () => {
    try {
      const { data } = await fetchTasks();
      setTasks(data);
    } catch (err) { console.log(err); }
  };

  useEffect(() => { if(token) getTasks(); }, [token]);

  return (
    <div className="min-h-screen text-white bg-[#0f172a] relative">
      {/* Navbar ko controls pass karo */}
      <Navbar onLoginClick={() => setAuthMode('login')} onSignupClick={() => setAuthMode('signup')} />

      {/* Auth Modals (Chote Size Mein) */}
      {authMode && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
          <div className="relative w-full max-w-sm">
            <button 
              onClick={() => setAuthMode(null)} 
              className="absolute -top-10 right-0 text-white/50 hover:text-white"
            > Close </button>
            {authMode === 'login' ? <Login /> : <Signup />}
          </div>
        </div>
      )}

      <AddTaskModal isOpen={isTaskModalOpen} onClose={() => setIsTaskModalOpen(false)} refreshTasks={getTasks} />

      <main className="pt-28 pb-12 px-6 max-w-7xl mx-auto min-h-[80vh]">
        <header className="mb-10">
          <h1 className="text-4xl font-black">Hi, {userName} 👋</h1>
          {token ? (
            <p className="text-gray-400 mt-2">Managing tasks as <span className="text-purple-400 font-bold">{userRole}</span></p>
          ) : (
            <p className="text-red-400 mt-2 italic font-bold text-sm">! Please Login to see and manage team tasks</p>
          )}
        </header>

        {/* Stats Section (Tabhi dikhe jab login ho) */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-10 opacity-90">
            <div className="p-6 bg-white/5 border border-white/10 rounded-3xl">
              <div className="text-blue-400"><LayoutDashboard size={20}/></div>
              <div className="text-3xl font-bold mt-2">{token ? tasks.length : '--'}</div>
              <div className="text-gray-500 text-[10px] uppercase tracking-widest">Tasks</div>
            </div>
            {/* ... Baki stats bhi aise hi daal do */}
        </div>

        <div className="flex justify-between items-center mb-8">
          <h2 className="text-2xl font-bold text-white/90">Project Board</h2>
          {token && userRole === 'admin' && (
            <button onClick={() => setIsTaskModalOpen(true)} className="bg-indigo-600 px-6 py-3 rounded-2xl font-bold flex items-center gap-2">
              <Plus size={20} /> New Task
            </button>
          )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {token ? (
            tasks.map((task) => <TaskCard key={task._id} task={task} refreshTasks={getTasks} />)
          ) : (
            <div className="col-span-full py-20 text-center bg-white/5 rounded-3xl border border-dashed border-white/10">
              <p className="text-gray-500">Access Restricted. Join the team to view board.</p>
            </div>
          )}
        </div>
      </main>
      <Footer />
    </div>
  );
};

export default Dashboard;
